import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { register } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import './Auth.css';

export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'patient' });
  const [loading, setLoading] = useState(false);
  const { loginUser } = useAuth();
  const navigate = useNavigate();

  const handle = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async (e) => {
    e.preventDefault();
    if (form.password.length < 6) { toast.error('Password must be at least 6 characters'); return; }
    setLoading(true);
    try {
      await register(form);
      // Auto-login after register
      const { login } = await import('../services/api');
      const res = await login({ email: form.email, password: form.password });
      loginUser(res.data.access_token, res.data.user);
      toast.success('Account created! Welcome to MediMind 🎉');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card card fade-up">
        <div className="auth-logo">⚕ MediMind</div>
        <h2 className="auth-title">Create Account</h2>
        <p className="auth-sub">Free forever. No credit card required.</p>

        <form onSubmit={submit}>
          <div className="form-group">
            <label>Full Name</label>
            <input className="form-input" name="name" value={form.name}
              onChange={handle} placeholder="Dr. Jane Smith" required />
          </div>
          <div className="form-group">
            <label>Email</label>
            <input className="form-input" type="email" name="email"
              value={form.email} onChange={handle} placeholder="you@example.com" required />
          </div>
          <div className="form-group">
            <label>Password</label>
            <input className="form-input" type="password" name="password"
              value={form.password} onChange={handle} placeholder="Min. 6 characters" required />
          </div>
          <div className="form-group">
            <label>I am a</label>
            <select className="form-input" name="role" value={form.role} onChange={handle}>
              <option value="patient">Patient</option>
              <option value="healthcare_worker">Healthcare Worker / Pharmacist</option>
            </select>
          </div>
          <button type="submit" className="btn btn-primary auth-btn" disabled={loading}>
            {loading ? <><span className="spinner" style={{width:18,height:18}}></span> Creating...</> : 'Create Account'}
          </button>
        </form>

        <p className="auth-switch">
          Already have an account? <Link to="/login">Login</Link>
        </p>
      </div>
    </div>
  );
}
